import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerStrings, MyTable, headerActions, breadCrumbActions, mainStageHeaderAction, mainStageHeaderStrings, InfoText } from '../../../includes';
import { Button } from '@material-ui/core';
import { colors } from '../../../../utils';
import { staffStrings } from '../config';
import { staffActions } from '../actions';
import { routeNamesSchool } from '../../routeNames';

const style = theme => ({
    root: {
        marginTop : 20
    },
    newBtn : {
        backgroundColor : colors.secondary
    }
})
class _AdminStaff extends Component {
    constructor(props) {
        super(props);
        headerActions({
            [headerStrings.headerTitle] : "Staff (Admin)",
            [headerStrings.backButtonAction] : null
        })(props.dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesSchool.dashboard},
            {name : "Admin Staff", path : routeNamesSchool.adminStaff},
        ])(props.dispatch);
    }
    componentDidMount(){
        const {dispatch} = this.props;
        mainStageHeaderAction({
            [mainStageHeaderStrings.buttons] : [{
                value : "New Admin Staff", className : this.props.classes.newBtn, 
                onClick : ()=>this.props.history.push(routeNamesSchool.newAdminStaff)
            }]
        })(dispatch);
        staffActions.getStaff.admins()(dispatch);
    }
    newStaffButton = () => <Button style={{backgroundColor : colors.secondary}}>New Staff</Button>;
    header = ["", "Last Name", "First Name", "Address", "Email", "Phone"];
    dataMap = ["action", "lastName", "firstName", "address", "email", "phone"]
    render() {
        const {classes, [staffStrings.staffListAdmin] : adminStaff = []} = this.props;
        return (
            <div className={classes.root}>
                <InfoText>Click on the table row (staff) to select</InfoText>
                <MyTable
                    header={this.header}
                    dataMap={this.dataMap}
                    data={adminStaff}/>
            </div>
        );
    }
}


_AdminStaff.propTypes = {
    classes : PropTypes.object.isRequired
};

const mapStateToProps = ({staffReducer}) => ({
    [staffStrings.staffListAdmin] : staffReducer[staffStrings.staffListAdmin]
})


export const AdminStaff = connect(mapStateToProps)(withStyles(style)(_AdminStaff));
export {AdminStaff as default};